  width: 100%;
  display: flex;
  justify-content: center;
  box-sizing: border-box;
  
  /* СТРОГО ЗАДАЕМ МАКЕТНЫЕ ОТСТУПЫ: */
  padding-left: 120px;
  padding-right: 124.17px;
}

.promo__container {
  width: 100%;              /* Меняем жесткие 1196px на 100%, чтобы контейнер гибко сидел между паддингами */
  max-width: 1196px;        /* Ограничиваем максимальную макетную ширину */
  height: 168px;           
  box-sizing: border-box;
  
  display: flex;
  flex-direction: column;
  align-items: center;     
  justify-content: center; 
  text-align: center;
}
